# Typical azuredeploy.parameters.json extracted from Portal Accelerator export
# Key parameters the wizard configures — extracted and tracked in git.

cat << 'EOF' > azuredeploy.parameters.json
{
  "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentParameters.json#",
  "contentVersion": "1.0.0.0",
  "parameters": {
    "enterpriseScaleCompanyPrefix": {
      "value": "alz"
    },
    "managementSubscriptionId": {
      "value": "<management-sub-id>"
    },
    "connectivitySubscriptionId": {
      "value": "<connectivity-sub-id>"
    },
    "identitySubscriptionId": {
      "value": "<identity-sub-id>"
    },
    "enableLogAnalytics": {
      "value": "Yes"
    },
    "enableAzureMonitorBaseline": {
      "value": "Yes"
    },
    "enableMicrosoftSentinel": {
      "value": "No"
    },
    "enableDefenderForCloud": {
      "value": "Yes"
    },
    "connectivityTopology": {
      "value": "HubAndSpoke"
    },
    "hubNetworkCIDR": {
      "value": "10.0.0.0/16"
    },
    "enableAzureFirewall": {
      "value": "Yes"
    },
    "enableVpnGateway": {
      "value": "No"
    },
    "enableExpressRoute": {
      "value": "No"
    },
    "enablePrivateDnsZones": {
      "value": "Yes"
    },
    "location": {
      "value": "eastus"
    }
  }
}
EOF

# Store this file in git — it documents the exact choices made in the wizard.
git add azuredeploy.parameters.json
git commit -m 'docs: capture portal accelerator parameter choices'
